import{_ as e,c as a,o as l,ag as i}from"./chunks/framework.DD2hp6gW.js";const f=JSON.parse('{"title":"Addon Builder","description":"","frontmatter":{},"headers":[],"relativePath":"builder.md","filePath":"builder.md","lastUpdated":1777120286000}'),r={name:"builder.md"};function o(n,t,s,d,h,g){return l(),a("div",null,t[0]||(t[0]=[i('<h1 id="addon-builder" tabindex="-1">Addon Builder <a class="header-anchor" href="#addon-builder" aria-label="Permalink to &quot;Addon Builder&quot;">​</a></h1><p>The <strong>Addon Builder</strong> is the heart of OptionBay. It&#39;s a powerful, drag-and-drop React interface that allows you to build complex product customization forms with ease.</p><h2 id="interface-overview" tabindex="-1">Interface Overview <a class="header-anchor" href="#interface-overview" aria-label="Permalink to &quot;Interface Overview&quot;">​</a></h2><p>When you edit an Option Group, you are presented with the Builder interface.</p><ol><li><strong>Toolbar:</strong> Contains the <strong>Add Field</strong> button and the <strong>Save</strong> controls.</li><li><strong>Field List:</strong> Your current fields, which you can drag to reorder.</li><li><strong>Settings Panel:</strong> Appears when you click on a field to edit its specific configuration.</li></ol><h2 id="available-field-types" tabindex="-1">Available Field Types <a class="header-anchor" href="#available-field-types" aria-label="Permalink to &quot;Available Field Types&quot;">​</a></h2><p>OptionBay supports a wide range of input types to cover every use case:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Field Type</th><th style="text-align:left;">Best For...</th></tr></thead><tbody><tr><td style="text-align:left;"><strong><a href="./fields/text.html">Text</a></strong></td><td style="text-align:left;">Single line inputs like names or short messages.</td></tr><tr><td style="text-align:left;"><strong><a href="./fields/textarea.html">Textarea</a></strong></td><td style="text-align:left;">Longer messages like &quot;Gift Note&quot; or &quot;Special Instructions&quot;.</td></tr><tr><td style="text-align:left;"><strong><a href="./fields/number.html">Number</a></strong></td><td style="text-align:left;">Quantities, dimensions, or any numeric data.</td></tr><tr><td style="text-align:left;"><strong><a href="./fields/select.html">Select</a></strong></td><td style="text-align:left;">Dropdown lists for choosing one item from many.</td></tr><tr><td style="text-align:left;"><strong><a href="./fields/radio.html">Radio</a></strong></td><td style="text-align:left;">Choosing one option where all choices are visible.</td></tr><tr><td style="text-align:left;"><strong><a href="./fields/checkbox.html">Checkbox</a></strong></td><td style="text-align:left;">Selecting multiple items from a list.</td></tr><tr><td style="text-align:left;"><strong><a href="./fields/single-checkbox.html">Single Checkbox</a></strong></td><td style="text-align:left;">A simple toggle (Yes/No) for things like &quot;Add Warranty&quot;.</td></tr><tr><td style="text-align:left;"><strong><a href="./fields/image-swatch.html">Image Swatches</a></strong></td><td style="text-align:left;">Choosing between patterns, materials, or styles visually.</td></tr><tr><td style="text-align:left;"><strong><a href="./fields/color-swatch.html">Color Swatches</a></strong></td><td style="text-align:left;">Selecting colors from a palette.</td></tr><tr><td style="text-align:left;"><strong><a href="./fields/file-upload.html">File Upload</a></strong></td><td style="text-align:left;">Collecting logos, photos, or documents from customers.</td></tr><tr><td style="text-align:left;"><strong><a href="./fields/email.html">Email</a></strong></td><td style="text-align:left;">Capturing an email address for digital delivery or contact info.</td></tr></tbody></table><h2 id="common-field-settings" tabindex="-1">Common Field Settings <a class="header-anchor" href="#common-field-settings" aria-label="Permalink to &quot;Common Field Settings&quot;">​</a></h2><p>Every field has a set of common attributes you can configure:</p><h3 id="general-settings" tabindex="-1">General Settings <a class="header-anchor" href="#general-settings" aria-label="Permalink to &quot;General Settings&quot;">​</a></h3><ul><li><strong>Label:</strong> The title of the field shown to the customer.</li><li><strong>Description:</strong> Helpful instructions shown below the input.</li><li><strong>Required:</strong> If checked, the customer must fill this field before they can add the product to their cart.</li></ul><h3 id="pricing-weight-settings" tabindex="-1">Pricing &amp; Weight Settings <a class="header-anchor" href="#pricing-weight-settings" aria-label="Permalink to &quot;Pricing &amp; Weight Settings&quot;">​</a></h3><p>You can attach costs and physical weight to almost any field:</p><ul><li><strong>Price Type:</strong><ul><li><strong>Flat Fee:</strong> A fixed cost.</li><li><strong>Percentage Increase:</strong> Adds a percentage of the base product price.</li><li><strong>Character Count:</strong> Cost multiplied by the number of characters typed (for text fields).</li><li><strong>Formula:</strong> Advanced math-based pricing.</li></ul></li><li><strong>Price:</strong> The numeric amount to add to the product total.</li><li><strong>Formula:</strong> (Only for Formula type) Use placeholders like <code>[char_count]</code>, <code>[base_price]</code>, <code>[quantity]</code>, or <code>[value]</code> to build complex calculations.</li><li><strong>Weight:</strong> The amount of physical weight to add to the product (affects shipping calculations).</li></ul><h3 id="appearance" tabindex="-1">Appearance <a class="header-anchor" href="#appearance" aria-label="Permalink to &quot;Appearance&quot;">​</a></h3><ul><li><strong>Placeholder:</strong> Ghost text shown inside the input (available for Text, Textarea, and Number fields).</li></ul><h2 id="reordering-fields" tabindex="-1">Reordering Fields <a class="header-anchor" href="#reordering-fields" aria-label="Permalink to &quot;Reordering Fields&quot;">​</a></h2><p>To change the order in which fields appear on the product page, simply grab the handle on the left of any field in the builder list and drag it to your preferred position.</p><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="./conditional-logic.html">Setting up Conditional Logic</a></li><li><a href="./assignments.html">Managing Product Assignments</a></li></ul>',21)]))}const u=e(r,[["render",o]]);export{f as __pageData,u as default};
